******************************************************************************/
void detachCfgThread(void){ cfg_thread.detach();}

/*!****************************************************************************
 @Function		StringTrim
 @Return		string		
 @Description	Function to trim leading and trailing whitespace from a string.
******************************************************************************/
std::string StringTrim(const std::string& str){

 	size_t first = str.find_first_not_of(' ');
    size_t last = str.find_last_not_of(' ');
    return str.substr(first, (last - first + 1));
}

/*!****************************************************************************
 @Function		ReadClusterCfg();
 @Return		string		
 @Description	Function to read the test configuration file from directory and store in .
******************************************************************************/
static bool ReadClusterCfg(void){

	/*get the current directory path*/
	char cur_dir[MAX_CFG_PATH_SIZE];
	char cfg_path[MAX_CFG_PATH_SIZE];

    // Wrapper for getcwd function for dependency injection
    auto getCurDir = [](char* buf, size_t size) {
        return getcwd(buf, size);
    };

	if(getCurDir(cur_dir,sizeof(cur_dir)) == NULL){

		return false;
	}

	snprintf(cfg_path,sizeof(cfg_path),"%s/%s",cur_dir,CFG_FILE_PATH);

	std::ifstream file(cfg_path);
    if (!file.is_open()) {
        std::cerr << "Failed to open the .ini file." << std::endl;
        file.close();
        return false;
    }
    else
    {
        std::map<std::string, std::map<std::string, std::string>> iniData;
        std::string currentSection;

        std::string line;
        while (std::getline(file, line)) {
            //line = trim(line);

            if (line.empty() || line[0] == ';') {
                // Skip empty lines and comments.
                continue;
            } else if (line[0] == '[' && line[line.length() - 1] == ']') {
                // Found a section.
                currentSection = line.substr(1, line.length() - 2);
            } else {
                // Found a key-value pair.
                size_t delimiterPos = line.find('=');
                if (delimiterPos != std::string::npos) {
                    std::string key = StringTrim(line.substr(0, delimiterPos));
                    std::string value = StringTrim(line.substr(delimiterPos + 1));
                    iniData[currentSection][key] = value;
                }
            }
        }

        // Accessing values from the .ini file.
        for (const auto & section : iniData) {


            if (section.first == "CurrentDisplay"){
                for (const auto & entry : section.second) {
                    if(entry.first =="name")sprintf(currentDisplay,(entry.second).c_str()); 
                }

            }
            else if (section.first == "HomeDisplay"){
                for (const auto & entry : section.second) {
                    if(entry.first == "name")sprintf(m_parameterInfo[eHomeDisplay].disp_name,(entry.second).c_str()); 
                    if(entry.first  == "width")m_parameterInfo[eHomeDisplay].width  = stoi(entry.second);
                    if(entry.first  == "height")m_parameterInfo[eHomeDisplay].height  = stoi(entry.second);

                }
            }
            else if (section.first == "WideDisplay"){
                for (const auto & entry : section.second) {
                    if(entry.first == "name")sprintf(m_parameterInfo[eWideDisplay].disp_name,(entry.second).c_str()); 
                    if(entry.first  == "width")m_parameterInfo[eWideDisplay].width  = stoi(entry.second);
                    if(entry.first  == "height")m_parameterInfo[eWideDisplay].height  = stoi(entry.second);

                }
            }
            else if (section.first == "DesktopDisplay"){
                for (const auto & entry : section.second) {
                    if(entry.first == "name")sprintf(m_parameterInfo[eDesktopDisplay].disp_name,(entry.second).c_str()); 
                    if(entry.first  == "width")m_parameterInfo[eDesktopDisplay].width  = stoi(entry.second);
                    if(entry.first  == "height")m_parameterInfo[eDesktopDisplay].height  = stoi(entry.second);

                }
            }
            else if (section.first == "Gaugues"){
                for (const auto & entry : section.second) {

                    if(entry.first  == "speed")tmp_speedVal  = stoi(entry.second);
                    if(entry.first  == "tacho")tmp_tachoVal  = stoi(entry.second);  
                    if(entry.first == "gear"){

                        if(entry.second == "D")sprintf(gaugue.gear,(entry.second).c_str());
                        else if(entry.second == "N")sprintf(gaugue.gear,(entry.second).c_str());
                        else if(entry.second == "R")sprintf(gaugue.gear,(entry.second).c_str());
                        else if(entry.second == "P")sprintf(gaugue.gear,(entry.second).c_str());
                        else sprintf(gaugue.gear,"Err");

                }
            }
            }
            else if (section.first == "Mode"){
                for (const auto & entry : section.second) {
                    if(entry.first  == "mode")mode  = stoi(entry.second);

                }
            }
            else if (section.first == "Display"){
                for (const auto & entry : section.second) {
                    if(entry.first  == "display")display_mode  = stoi(entry.second);

                }
            }

            }

        file.close();
        return true;
    }
}

/*!****************************************************************************
 @Function		getDisplay();
 @param         const char * currentDisp
 @Return		int		
 @Description	Function to get the current display from cofiguration file.
******************************************************************************/
static int getDisplay(const char* currentDisp){

    if(strcmp(currentDisp, "HomeDisplay") == 0){return (int) eHomeDisplay;}
    else if(strcmp(currentDisp, "WideDisplay") == 0){ return (int) eWideDisplay;}
    else { return (int) eDesktopDisplay;}

}
/*!****************************************************************************
 @Function		getCfgCurrentDisplay();
 @Return		int	as current dispaly	
 @Description	Function to exposed to get the current display from cofiguration file
                0 = Home Dispaly
                1 = Wide Display
                2 = Desktop Dispaly.
******************************************************************************/
int getCfgCurrentDisplay(void){
    return getDisplay(currentDisplay);
}
/*!****************************************************************************
 @Function		updateDisplay();
 @Return		1	as Success
 @Return		0	as Fail
 @Description	Update the width and Height of Dispaly
******************************************************************************/
static int updateDisplay(const char* currentDisp){
    int ret = false;

    switch (getDisplay(currentDisp))
    {
    case eHomeDisplay :
        sprintf(cluster_screen.disp_name,currentDisp);
        cluster_screen.width = m_parameterInfo[eHomeDisplay].width;
        cluster_screen.height = m_parameterInfo[eHomeDisplay].height;
        break;
    case eWideDisplay :
        sprintf(cluster_screen.disp_name,currentDisp);
        cluster_screen.width = m_parameterInfo[eWideDisplay].width;
        cluster_screen.height = m_parameterInfo[eWideDisplay].height;
        break;
    case eDesktopDisplay :
        sprintf(cluster_screen.disp_name,currentDisp);
        cluster_screen.width = m_parameterInfo[eDesktopDisplay].width;
        cluster_screen.height = m_parameterInfo[eDesktopDisplay].height;
        break;

    default:
        break;
    }

    ret = true;
    return ret;
}
/*!****************************************************************************
 @Function		tachoNeedleRotation();
 @Return		void
 @Description	Update the tachometer while it is in mode-1
******************************************************************************/
static void tachoNeedleRotation(void){

    const int rotationTimeinSec = 2000; //one full rotation in 2 sec

    for (int i = 0; i <= TACHO_GAUGE_MAX; i++){
        gaugue.tacho = i;
        usleep(rotationTimeinSec * 1000 / TACHO_GAUGE_MAX);
    }

}
/*!****************************************************************************
 @Function		speedoNeedleRotation();
 @Return		void
 @Description	Update the Spedometer while it is in mode-1
******************************************************************************/
static void speedoNeedleRotation(void){

    const int rotationTimeinSec = 2000; //one full rotation in 2 sec

    for (int i = 0; i <= SPEED_GAUGE_MAX; i++){
        gaugue.speed = i;
        usleep(rotationTimeinSec * 1000 / SPEED_GAUGE_MAX);

    }

}

/*!****************************************************************************
 @Function		CfgRunner();
 @Return		int		
 @Description	Runner function that update the runtime changes in configuration file .
******************************************************************************/
static bool CfgRunner (void ){

    int persist_mode = 0;

	while(!is_thread_exit){

        cfgReadStatus = ReadClusterCfg(); 
		if( cfgReadStatus == false){ /*If the file is not exist:ASDBPAP-2816 */

            is_thread_exit = true;
            break;
        }
        else{

            updateDisplay(currentDisplay);
            if (mode)
            {
                if (mode != persist_mode)
                {

                    gaugetacho_thread  = std::thread(tachoNeedleRotation);
                    gaugespeedo_thread = std::thread(speedoNeedleRotation);
                    gaugespeedo_thread.join();
                    gaugetacho_thread.join();
                    persist_mode       = mode;
                }
            }
            else
            {
                persist_mode = 0;
                gaugue.speed = tmp_speedVal;
                gaugue.tacho = tmp_tachoVal;
            }
        }
		sleep(2);
	}
    return true;
}

